Here's a complete implementation:

**XAML (e.g., `ItemsPage.xaml`)**

```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             xmlns:vm="clr-namespace:MyApp.ViewModels"
             x:Class="MyApp.Views.ItemsPage"
             x:DataType="vm:ItemsViewModel">

    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem}"
                    IsRefreshing="{Binding IsRefreshing}"
                    RemainingItemsThreshold="0">

        <!-- Pull-to-refresh via RefreshView wrapper -->
        <CollectionView.Behaviors>
            <!-- If using CommunityToolkit, you can attach behaviors here -->
        </CollectionView.Behaviors>

        <CollectionView.ItemTemplate>
            <DataTemplate x:DataType="vm:ItemModel">
                <VerticalStackLayout Padding="12" Spacing="4">
                    <Label Text="{Binding Title}" FontSize="18" FontAttributes="Bold" />
                    <Label Text="{Binding Description}" FontSize="14" TextColor="Gray" />
                </VerticalStackLayout>
            </DataTemplate>
        </CollectionView.ItemTemplate>

        <CollectionView.EmptyView>
            <Label Text="No items found." HorizontalOptions="Center" VerticalOptions="Center" />
        </CollectionView.EmptyView>
    </CollectionView>

</ContentPage>
```

Since `CollectionView` doesn't natively support pull-to-refresh, wrap it in a `RefreshView`:

```xml
<RefreshView Command="{Binding RefreshCommand}"
             IsRefreshing="{Binding IsRefreshing}">

    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem}">
        <!-- ItemTemplate as above -->
    </CollectionView>

</RefreshView>
```

**ViewModel (`ItemsViewModel.cs`)**

```csharp
using CommunityToolkit.Mvvm.ComponentModel;
using CommunityToolkit.Mvvm.Input;
using System.Collections.ObjectModel;

public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    public ObservableCollection<ItemModel> Items { get; } = new();

    [ObservableProperty]
    private ItemModel? _selectedItem;

    [ObservableProperty]
    private bool _isRefreshing;

    public ItemsViewModel(IApiService api, INavigationService nav)
    {
        _api = api;
        _nav = nav;
    }

    // Fires when SelectedItem changes via source generator
    partial void OnSelectedItemChanged(ItemModel? value)
    {
        if (value is not null)
            NavigateToDetailCommand.Execute(value);
    }

    [RelayCommand]
    private async Task NavigateToDetailAsync(ItemModel item)
    {
        // Clear selection so the user can re-select the same item later
        SelectedItem = null;

        await _nav.GoToAsync(nameof(DetailPage), new Dictionary<string, object>
        {
            { "Item", item }
        });
    }

    [RelayCommand]
    private async Task RefreshAsync()
    {
        try
        {
            IsRefreshing = true;
            var freshData = await _api.GetItemsAsync();

            Items.Clear();
            foreach (var item in freshData)
                Items.Add(item);
        }
        finally
        {
            IsRefreshing = false;
        }
    }
}
```

**Key binding relationships:**

| XAML Property | ViewModel Property | Purpose |
|---|---|---|
| `ItemsSource` | `ObservableCollection<T> Items` | Drives the list; auto-updates UI on add/remove |
| `SelectedItem` | `ItemModel? SelectedItem` | Two-way by default — triggers navigation via `OnSelectedItemChanged` |
| `RefreshView.Command` | `RefreshCommand` | Generated by `[RelayCommand]` on `RefreshAsync` |
| `RefreshView.IsRefreshing` | `bool IsRefreshing` | Set `false` when done to stop the spinner |

**Important notes:**

1. **Reset `SelectedItem` to `null`** after navigating — otherwise the same item can't be re-selected.
2. **`IsRefreshing = false`** must be set in `finally` so the spinner stops even on errors.
3. **`RefreshView` wraps `CollectionView`** — `CollectionView` itself has no pull-to-refresh support.
4. Uses **CommunityToolkit.Mvvm** source generators (`[ObservableProperty]`, `[RelayCommand]`) to eliminate boilerplate.
